const TYPE_LABELS = {
  bank: 'Bank Account',
  investments: 'Investment',
  property: 'Property',
  vehicles: 'Vehicle',
  rentals: 'Rental',
  inflows: 'Inflow',
  outflows: 'Outflow'
};
const TYPE_ICONS = {
  bank:        'bi-bank',
  investments: 'bi-bar-chart-line',
  property:    'bi-house',
  vehicles:    'bi-car-front',
  rentals:     'bi-building',
  inflows:     'bi-arrow-down-circle',
  outflows:    'bi-arrow-up-circle'
};
const SECTION_META = {
  dashboard:   { title: 'Dashboard',      subtitle: 'Overview of your retirement plan' },
  bank:        { title: 'Bank Accounts',  subtitle: 'Manage your bank and savings accounts' },
  investments: { title: 'Investments',    subtitle: 'Stocks, ETFs, super, and more' },
  property:    { title: 'Property',       subtitle: 'Real estate and land holdings' },
  vehicles:    { title: 'Vehicles',       subtitle: 'Cars, boats, and other vehicles' },
  rentals:     { title: 'Rentals',        subtitle: 'Rental income properties' },
  inflows:     { title: 'Inflows',        subtitle: 'Salary, pension, dividends, and other income' },
  outflows:    { title: 'Outflows',       subtitle: 'Living expenses, mortgage, tax, and more' }
};
function _escapeHtml(str) {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}


// --- js/appState.js ---
// =============================================================================
// App State — shared mutable state object
// All modules import `state` and read/write its properties directly.
// =============================================================================

const _loaded = loadState();
const state = {
  items: _loaded.items,
  settings: _loaded.settings,
  activeSection: 'dashboard',
  chartInstance: null
};


// --- js/renderer.js ---
// =============================================================================
// Renderer
// =============================================================================





// Track per-item chart instances so we can destroy them on re-render
var _itemCharts = {};
function renderItemList() {
  const listArea = document.getElementById('item-list-area');
  const statsRow = document.getElementById('stats-row');
  const chartContainer = document.getElementById('chart-container');

  if (state.activeSection === 'dashboard') {
    if (listArea) listArea.style.display = 'none';
    if (statsRow) statsRow.style.display = '';
    if (chartContainer) chartContainer.style.display = '';
    return;
  }
  if (statsRow) statsRow.style.display = 'none';
  if (chartContainer) chartContainer.style.display = 'none';
  if (listArea) listArea.style.display = '';

  const filtered = state.items.filter(item => item.type === state.activeSection);
  if (!listArea) return;
  if (filtered.length === 0) { renderEmptyState(); return; }

  const projEnd = state.settings.startYear + state.settings.projectionYears - 1;
  const rows = filtered.map((item) => {
    const idx = state.items.indexOf(item);
    const icon = TYPE_ICONS[item.type] || 'bi-circle';
    const rs = item.rate > 0 ? '+' : '';
    const yr = item.endYear == null ? (item.startYear + ' \u2013 ongoing') : (item.startYear + '\u2013' + item.endYear);
    const meta = item.category + ' \u00B7 ' + yr + ' \u00B7 ' + rs + item.rate + '%';
    var extra = '';
    if (item.contributionAmount > 0 && item.contributionFrequency) {
      var contribText = '+' + formatMoney(item.contributionAmount) + (item.contributionFrequency === 'monthly' ? '/mo' : '/yr') + ' contribution';
      if (item.contributionEndYear != null) contribText += ' (until ' + item.contributionEndYear + ')';
      extra += '<div class="item-meta">' + contribText + '</div>';
    }
    if (item.withdrawalAmount > 0 && item.withdrawalFrequency) {
      extra += '<div class="item-meta">\u2212' + formatMoney(item.withdrawalAmount) + (item.withdrawalFrequency === 'monthly' ? '/mo' : '/yr') + ' withdrawal</div>';
    }
    if (item.loan) {
      var sch = calcLoanSchedule(item.loan, item.startYear, projEnd);
      var lb = sch.length > 0 ? sch[0].closingBalance : item.loan.loanAmount;
      var eq = Math.max(0, calcItemValue(item, item.startYear) - lb);
      extra += '<div class="item-meta">Loan: ' + formatMoney(lb) + ' balance \u00B7 Equity: ' + formatMoney(eq) + '</div>';
      var payoffYear = getLoanPayoffYear(sch);
      if (payoffYear != null) {
        extra += '<div class="item-meta">Paid off: ' + payoffYear + '</div>';
      } else {
        extra += '<div class="item-meta">Paid off: beyond ' + projEnd + '</div>';
      }
    }
    if (item.retirement401k) {
      var r = item.retirement401k, ec = r.employeeContribution || 0;
      var ma = Math.min(ec, (r.annualSalary || 0) * (r.employerMatchCapPct || 0) / 100) * (r.employerMatchPct || 0) / 100;
      extra += '<div class="item-meta">Employee: ' + formatMoney(ec) + '/yr \u00B7 Match: ' + formatMoney(ma) + '/yr</div>';
    }
    var ldh = '';
    if (item.loan) {
      var ls = calcLoanSchedule(item.loan, item.startYear, projEnd), tr = '';
      for (var i = 0; i < ls.length; i++) { var s = ls[i]; tr += '<tr><td>'+s.year+'</td><td>'+formatMoney(s.openingBalance)+'</td><td>'+formatMoney(s.principalPaid)+'</td><td>'+formatMoney(s.interestPaid)+'</td><td>'+formatMoney(s.escrowPaid)+'</td><td>'+formatMoney(s.closingBalance)+'</td></tr>'; }
      ldh = '<div class="loan-details-section"><button class="btn btn-sm btn-outline-secondary loan-details-toggle" onclick="this.parentElement.classList.toggle(\'expanded\')"><i class="bi bi-chevron-down"></i> Loan Details</button><div class="loan-details-table-wrapper"><table class="table table-sm loan-details-table"><thead><tr><th>Year</th><th>Opening</th><th>Principal</th><th>Interest</th><th>Escrow</th><th>Closing</th></tr></thead><tbody>'+tr+'</tbody></table></div></div>';
    }
    return '<div class="item-row" data-item-index="'+idx+'"><i class="bi '+icon+' item-icon"></i><div class="flex-grow-1"><div class="item-name">'+_escapeHtml(item.name)+'</div><div class="item-meta">'+_escapeHtml(meta)+'</div>'+extra+ldh+'<div class="item-chart-section" id="item-chart-section-'+idx+'" style="display:none"><canvas id="item-chart-'+idx+'" height="150"></canvas></div></div><div class="item-value">'+formatMoney(item.amount)+'</div><div class="item-action-area"><button class="btn btn-sm btn-outline-secondary" onclick="toggleItemChart('+idx+')" title="Chart"><i class="bi bi-graph-up"></i></button><button class="btn btn-sm btn-outline-secondary" onclick="openEditModal('+idx+')" title="Edit"><i class="bi bi-pencil"></i></button><button class="btn btn-sm btn-outline-danger" onclick="initiateDelete('+idx+')" title="Delete"><i class="bi bi-trash"></i></button></div></div>';
  });
  listArea.innerHTML = '<div class="card card-surface">' + rows.join('') + '</div>';
}
function toggleItemChart(idx) {
  var section = document.getElementById('item-chart-section-' + idx);
  if (!section) return;

  // Toggle visibility
  if (section.style.display !== 'none') {
    section.style.display = 'none';
    if (_itemCharts[idx]) { _itemCharts[idx].destroy(); delete _itemCharts[idx]; }
    return;
  }
  section.style.display = '';

  var item = state.items[idx];
  if (!item) return;

  var startYear = state.settings.startYear;
  var projEnd = startYear + state.settings.projectionYears - 1;
  var effectiveEnd = item.endYear == null ? projEnd : Math.min(item.endYear, projEnd);
  var effectiveStart = Math.max(item.startYear, startYear);

  var years = [];
  var values = [];
  var balanceCache = {};

  var is401k = (item.category === 'Traditional 401(k)' || item.category === 'Roth 401(k)') && item.retirement401k;
  var hasContribOrWithdraw = (item.contributionAmount > 0) || (item.withdrawalAmount > 0);
  var hasLoan = item.loan && item.loan.loanAmount > 0;
  var loanSchedule = hasLoan ? calcLoanSchedule(item.loan, item.startYear, projEnd) : null;

  for (var y = effectiveStart; y <= effectiveEnd; y++) {
    years.push(y);
    var val = 0;

    if (item.type === 'inflows' || item.type === 'outflows') {
      val = item.amount;
    } else if (is401k) {
      val = calc401kBalance(item, y, balanceCache, projEnd);
    } else if (ASSET_TYPES.includes(item.type) && hasContribOrWithdraw) {
      val = calcItemBalance(item, y, balanceCache, projEnd);
    } else if (hasLoan && loanSchedule) {
      var assetVal = item.amount * Math.pow(1 + item.rate / 100, y - item.startYear);
      var entry = loanSchedule.find(function(e) { return e.year === y; });
      val = assetVal - (entry ? entry.closingBalance : 0);
    } else {
      val = item.amount * Math.pow(1 + item.rate / 100, y - item.startYear);
    }
    values.push(val);
  }

  var canvas = document.getElementById('item-chart-' + idx);
  if (!canvas) return;

  if (_itemCharts[idx]) { _itemCharts[idx].destroy(); }

  _itemCharts[idx] = new Chart(canvas.getContext('2d'), {
    type: 'line',
    data: {
      labels: years,
      datasets: [{
        label: item.name,
        data: values,
        borderColor: '#58a6ff',
        backgroundColor: 'rgba(88, 166, 255, 0.1)',
        fill: true,
        tension: 0.3,
        pointRadius: 2
      }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: {
        legend: { display: false },
        tooltip: {
          callbacks: {
            label: function(ctx) { return formatMoney(ctx.parsed.y); }
          }
        }
      },
      scales: {
        x: { ticks: { color: '#9e9e9e', maxTicksLimit: 10 }, grid: { color: 'rgba(255,255,255,0.05)' } },
        y: {
          ticks: {
            color: '#9e9e9e',
            callback: function(v) { return formatMoney(v); }
          },
          grid: { color: 'rgba(255,255,255,0.05)' }
        }
      }
    }
  });
}
function renderTaxBreakdown() {
  const panel = document.getElementById('taxBreakdownPanel');
  if (!panel) return;

  if (state.activeSection !== 'dashboard') {
    panel.style.display = 'none';
    return;
  }

  const proj = calcProjection(state.items, state.settings);
  if (proj.length === 0 || !proj[0].tax) {
    panel.style.display = 'none';
    return;
  }

  const tax = proj[0].tax;
  const filingStatus = (state.settings.tax && state.settings.tax.filingStatus) || 'single';
  const statusLabel = filingStatus === 'married_filing_jointly' ? 'Married Filing Jointly' : 'Single';

  panel.style.display = '';
  const setEl = (id, val) => { const el = document.getElementById(id); if (el) el.textContent = val; };
  setEl('tax-filingStatus', statusLabel);
  setEl('tax-ordinaryIncome', formatMoney(tax.ordinaryIncome));
  setEl('tax-ltcgIncome', formatMoney(tax.ltcgIncome));
  setEl('tax-taxableSS', formatMoney(tax.taxableSocialSecurity));
  setEl('tax-standardDeduction', formatMoney(tax.standardDeduction));
  setEl('tax-taxableOrdinaryIncome', formatMoney(tax.taxableOrdinaryIncome));
  setEl('tax-ordinaryTax', formatMoney(tax.ordinaryTax));
  setEl('tax-ltcgTax', formatMoney(tax.ltcgTax));
  setEl('tax-totalEstimatedTax', formatMoney(tax.totalEstimatedTax));
}
function renderEmptyState() {
  const listArea = document.getElementById('item-list-area');
  if (!listArea) return;
  const label = TYPE_LABELS[state.activeSection] || state.activeSection;
  listArea.innerHTML = '<div class="empty-state"><i class="bi '+(TYPE_ICONS[state.activeSection]||'bi-inbox')+'"></i><p>No '+label+' items yet.</p><p class="small">Click "Add '+label+'" to get started.</p></div>';
}
function updateBadges() {
  for (const type of ALL_TYPES) {
    const b = document.getElementById('badge-' + type);
    if (b) b.textContent = state.items.filter(i => i.type === type).length;
  }
  const addBtn = document.getElementById('btn-add-item');
  if (!addBtn) return;
  if (state.items.length >= MAX_ITEMS) {
    addBtn.disabled = true;
    let w = document.getElementById('max-items-warning');
    if (!w) { w = document.createElement('span'); w.id = 'max-items-warning'; w.className = 'badge bg-warning text-dark ms-2'; w.textContent = 'Max items reached'; addBtn.parentNode.insertBefore(w, addBtn.nextSibling); }
  } else {
    addBtn.disabled = false;
    const w = document.getElementById('max-items-warning');
    if (w) w.remove();
  }
}
function updateStats() {
  const s = calcStats(state.items, state.settings);
  const e1 = document.getElementById('stat-totalAssets');
  const e2 = document.getElementById('stat-annualInflow');
  const e3 = document.getElementById('stat-annualOutflow');
  if (e1) e1.textContent = formatMoney(s.totalAssets);
  if (e2) e2.textContent = formatMoney(s.annualInflow);
  if (e3) e3.textContent = formatMoney(s.annualOutflow);
}
function updateChart() {
  try {
    const canvas = document.getElementById('projectionChart');
    if (!canvas) return;
    const proj = calcProjection(state.items, state.settings);
    const years = proj.map(p => p.year);
    const theme = state.settings.theme || DEFAULT_SETTINGS.theme;
    const accent = theme.accent || '#58a6ff', textColor = theme.text || '#e0e0e0', gridColor = 'rgba(255,255,255,0.1)';
    const datasets = [{ label: 'Total Net Worth', data: proj.map(p => p.netWorth), borderColor: accent, backgroundColor: 'transparent', borderWidth: 2, pointRadius: 0, tension: 0.3 }];
    const tc = { bank:'#4fc3f7', investments:'#81c784', property:'#ffb74d', vehicles:'#e57373', rentals:'#ba68c8', inflows:'#4db6ac', outflows:'#f06292' };
    for (const type of ALL_TYPES) {
      if (!state.items.some(i => i.type === type)) continue;
      datasets.push({ label: TYPE_LABELS[type], data: proj.map(p => p.byType[type]), borderColor: tc[type]||'#aaa', backgroundColor: 'transparent', borderWidth: 1.5, borderDash: [5,5], pointRadius: 0, tension: 0.3 });
    }
    // Tax estimate dashed line
    if (proj.some(p => p.tax && p.tax.totalEstimatedTax > 0)) {
      datasets.push({ label: 'Est. Tax', data: proj.map(p => p.tax ? p.tax.totalEstimatedTax : 0), borderColor: '#ff7043', backgroundColor: 'transparent', borderWidth: 1.5, borderDash: [4,4], pointRadius: 0, tension: 0.3 });
    }
    // 401(k) per-type lines
    if (state.items.some(i => i.category === 'Traditional 401(k)')) {
      datasets.push({ label: 'Traditional 401(k)', data: proj.map(p => p.byType.traditional401k || 0), borderColor: '#ffd54f', backgroundColor: 'transparent', borderWidth: 1.5, borderDash: [6,3], pointRadius: 0, tension: 0.3 });
    }
    if (state.items.some(i => i.category === 'Roth 401(k)')) {
      datasets.push({ label: 'Roth 401(k)', data: proj.map(p => p.byType.roth401k || 0), borderColor: '#aed581', backgroundColor: 'transparent', borderWidth: 1.5, borderDash: [6,3], pointRadius: 0, tension: 0.3 });
    }
    const cfg = { type:'line', data:{labels:years,datasets}, options:{responsive:true,animation:false,plugins:{legend:{display:true,labels:{color:textColor,font:{size:12}}},title:{display:!!state.settings.chartTitle,text:state.settings.chartTitle||'',color:textColor}},scales:{x:{ticks:{color:textColor},grid:{color:gridColor}},y:{ticks:{color:textColor,callback:function(v){return formatMoney(v);}},grid:{color:gridColor}}}} };
    if (state.chartInstance) { state.chartInstance.data = cfg.data; state.chartInstance.options = cfg.options; state.chartInstance.update(); }
    else { state.chartInstance = new Chart(canvas, cfg); }
  } catch (err) { console.error('Chart render error:', err); }
}
function render() {
  const meta = SECTION_META[state.activeSection] || SECTION_META.dashboard;
  const titleEl = document.getElementById('section-title');
  const subtitleEl = document.getElementById('section-subtitle');
  if (titleEl) titleEl.textContent = meta.title;
  if (subtitleEl) subtitleEl.textContent = meta.subtitle;

  // Toggle add button visibility
  const addBtn = document.getElementById('btn-add-item');
  const addLabel = document.getElementById('btn-add-label');
  if (addBtn) {
    if (state.activeSection === 'dashboard') {
      addBtn.classList.add('d-none');
    } else {
      addBtn.classList.remove('d-none');
      if (addLabel) addLabel.textContent = 'Add ' + (TYPE_LABELS[state.activeSection] || 'Item');
    }
  }

  // Highlight active nav link
  const navLinks = document.querySelectorAll('#sidebar .nav-link[data-section]');
  navLinks.forEach(link => {
    if (link.dataset.section === state.activeSection) {
      link.classList.add('active');
    } else {
      link.classList.remove('active');
    }
  });

  // Tax breakdown panel visibility
  const taxPanel = document.getElementById('taxBreakdownPanel');
  if (taxPanel) {
    taxPanel.style.display = state.activeSection === 'dashboard' ? '' : 'none';
  }

  renderItemList();
  updateBadges();
  updateStats();
  updateChart();
  renderTaxBreakdown();
}


// --- js/modalController.js ---
// =============================================================================
// ModalController — openAddModal(type), openEditModal(index), closeModal()
//                   form submit handler, inline delete confirmation
// =============================================================================





function _getModal() {
  const el = document.getElementById('itemModal');
  if (!el) return null;
  return bootstrap.Modal.getOrCreateInstance(el);
}
function _populateCategorySelect(type) {
  const sel = document.getElementById('field-category');
  if (!sel) return;
  sel.innerHTML = '<option value="">Select category\u2026</option>';
  const cats = SUBCATEGORIES[type] || [];
  cats.forEach(cat => {
    const opt = document.createElement('option');
    opt.value = cat;
    opt.textContent = cat;
    sel.appendChild(opt);
  });
}
function _updateFieldGroupVisibility(type, category) {
  const contributionGroup = document.getElementById('contributionGroup');
  const withdrawalGroup = document.getElementById('withdrawalGroup');
  const loanGroup = document.getElementById('loanGroup');
  const retirement401kGroup = document.getElementById('retirement401kGroup');

  if (contributionGroup) {
    contributionGroup.style.display = (type === 'bank' || type === 'investments') ? '' : 'none';
  }
  if (withdrawalGroup) {
    withdrawalGroup.style.display = ASSET_TYPES.includes(type) ? '' : 'none';
  }
  if (loanGroup) {
    loanGroup.style.display = (type === 'property' || type === 'vehicles') ? '' : 'none';
  }
  if (retirement401kGroup) {
    retirement401kGroup.style.display = (category === 'Traditional 401(k)' || category === 'Roth 401(k)') ? '' : 'none';
  }
}

function _clearNewFields() {
  var ids = ['field-contributionAmount', 'field-contributionEndYear', 'field-loanAmount', 'field-loanRate',
    'field-loanPayment', 'field-loanEscrow', 'field-loanPropertyTax', 'field-loanExtra',
    'field-withdrawalAmount', 'field-employeeContribution', 'field-employerMatchPct',
    'field-matchCapPct', 'field-annualSalary', 'field-vestingYears', 'field-withdrawalStartYear'];
  ids.forEach(function(id) {
    var el = document.getElementById(id);
    if (el) el.value = '';
  });

  var contribFreq = document.getElementById('field-contributionFrequency');
  if (contribFreq) contribFreq.value = 'monthly';
  var withdrawFreq = document.getElementById('field-withdrawalFrequency');
  if (withdrawFreq) withdrawFreq.value = 'monthly';

  var noEndDate = document.getElementById('noEndDate');
  if (noEndDate) noEndDate.checked = false;
  var endYearField = document.getElementById('field-endYear');
  if (endYearField) {
    endYearField.disabled = false;
    endYearField.required = true;
  }
}
function openAddModal(type) {
  const label = TYPE_LABELS[type] || type;
  const titleEl = document.getElementById('itemModalLabel');
  if (titleEl) titleEl.textContent = 'Add ' + label;

  const typeField = document.getElementById('field-type');
  if (typeField) typeField.value = type;

  _populateCategorySelect(type);

  const nameField = document.getElementById('field-name');
  if (nameField) nameField.value = '';
  const amountField = document.getElementById('field-amount');
  if (amountField) amountField.value = '';
  const rateField = document.getElementById('field-rate');
  if (rateField) rateField.value = '0';
  const categoryField = document.getElementById('field-category');
  if (categoryField) categoryField.value = '';

  const startYearField = document.getElementById('field-startYear');
  if (startYearField) startYearField.value = state.settings.startYear;
  const endYearField = document.getElementById('field-endYear');
  if (endYearField) endYearField.value = state.settings.startYear + state.settings.projectionYears - 1;

  const editIndexField = document.getElementById('field-editIndex');
  if (editIndexField) editIndexField.value = '';

  const errorDiv = document.getElementById('modal-error');
  if (errorDiv) { errorDiv.textContent = ''; errorDiv.classList.add('d-none'); }

  _clearNewFields();
  _updateFieldGroupVisibility(type, '');

  const modal = _getModal();
  if (modal) modal.show();

  const modalEl = document.getElementById('itemModal');
  if (modalEl) {
    modalEl.addEventListener('shown.bs.modal', () => {
      const nf = document.getElementById('field-name');
      if (nf) nf.focus();
    }, { once: true });
  }
}
function openEditModal(index) {
  const item = state.items[index];
  if (!item) return;

  const label = TYPE_LABELS[item.type] || item.type;
  const titleEl = document.getElementById('itemModalLabel');
  if (titleEl) titleEl.textContent = 'Edit ' + label;

  const typeField = document.getElementById('field-type');
  if (typeField) typeField.value = item.type;

  _populateCategorySelect(item.type);
  const categoryField = document.getElementById('field-category');
  if (categoryField) categoryField.value = item.category;

  const nameField = document.getElementById('field-name');
  if (nameField) nameField.value = item.name;
  const amountField = document.getElementById('field-amount');
  if (amountField) amountField.value = item.amount;
  const rateField = document.getElementById('field-rate');
  if (rateField) rateField.value = item.rate != null ? item.rate : 0;
  const startYearField = document.getElementById('field-startYear');
  if (startYearField) startYearField.value = item.startYear;

  const endYearField = document.getElementById('field-endYear');
  const noEndDate = document.getElementById('noEndDate');
  if (item.endYear == null) {
    if (noEndDate) noEndDate.checked = true;
    if (endYearField) { endYearField.value = ''; endYearField.disabled = true; endYearField.required = false; }
  } else {
    if (noEndDate) noEndDate.checked = false;
    if (endYearField) { endYearField.value = item.endYear; endYearField.disabled = false; endYearField.required = true; }
  }

  const editIndexField = document.getElementById('field-editIndex');
  if (editIndexField) editIndexField.value = index;

  const errorDiv = document.getElementById('modal-error');
  if (errorDiv) { errorDiv.textContent = ''; errorDiv.classList.add('d-none'); }

  // Populate contribution fields
  const contribAmount = document.getElementById('field-contributionAmount');
  if (contribAmount) contribAmount.value = item.contributionAmount != null ? item.contributionAmount : '';
  const contribFreq = document.getElementById('field-contributionFrequency');
  if (contribFreq) contribFreq.value = item.contributionFrequency || 'monthly';
  const contribEndYear = document.getElementById('field-contributionEndYear');
  if (contribEndYear) contribEndYear.value = item.contributionEndYear != null ? item.contributionEndYear : '';

  // Populate withdrawal fields
  const withdrawAmount = document.getElementById('field-withdrawalAmount');
  if (withdrawAmount) withdrawAmount.value = item.withdrawalAmount != null ? item.withdrawalAmount : '';
  const withdrawFreq = document.getElementById('field-withdrawalFrequency');
  if (withdrawFreq) withdrawFreq.value = item.withdrawalFrequency || 'monthly';

  // Populate loan fields
  const loan = item.loan || {};
  const loanAmountField = document.getElementById('field-loanAmount');
  if (loanAmountField) loanAmountField.value = loan.loanAmount != null ? loan.loanAmount : '';
  const loanRateField = document.getElementById('field-loanRate');
  if (loanRateField) loanRateField.value = loan.annualInterestRate != null ? loan.annualInterestRate : '';
  const loanPaymentField = document.getElementById('field-loanPayment');
  if (loanPaymentField) loanPaymentField.value = loan.monthlyPayment != null ? loan.monthlyPayment : '';
  const loanEscrowField = document.getElementById('field-loanEscrow');
  if (loanEscrowField) loanEscrowField.value = loan.escrowMonthly != null ? loan.escrowMonthly : '';
  const loanPropertyTaxField = document.getElementById('field-loanPropertyTax');
  if (loanPropertyTaxField) loanPropertyTaxField.value = loan.propertyTaxAnnual != null ? loan.propertyTaxAnnual : '';
  const loanExtraField = document.getElementById('field-loanExtra');
  if (loanExtraField) loanExtraField.value = loan.extraMonthlyPayment != null ? loan.extraMonthlyPayment : '';

  // Populate 401(k) fields
  const r401k = item.retirement401k || {};
  const empContrib = document.getElementById('field-employeeContribution');
  if (empContrib) empContrib.value = r401k.employeeContribution != null ? r401k.employeeContribution : '';
  const empMatchPct = document.getElementById('field-employerMatchPct');
  if (empMatchPct) empMatchPct.value = r401k.employerMatchPct != null ? r401k.employerMatchPct : '';
  const matchCapPct = document.getElementById('field-matchCapPct');
  if (matchCapPct) matchCapPct.value = r401k.employerMatchCapPct != null ? r401k.employerMatchCapPct : '';
  const annualSalary = document.getElementById('field-annualSalary');
  if (annualSalary) annualSalary.value = r401k.annualSalary != null ? r401k.annualSalary : '';
  const vestingYears = document.getElementById('field-vestingYears');
  if (vestingYears) vestingYears.value = r401k.vestingYears != null ? r401k.vestingYears : '';
  const withdrawalStartYear = document.getElementById('field-withdrawalStartYear');
  if (withdrawalStartYear) withdrawalStartYear.value = r401k.withdrawalStartYear != null ? r401k.withdrawalStartYear : '';

  _updateFieldGroupVisibility(item.type, item.category);

  const modal = _getModal();
  if (modal) modal.show();
}
function closeModal() {
  const modal = _getModal();
  if (modal) modal.hide();
}

function _showModalError(message) {
  const errorDiv = document.getElementById('modal-error');
  if (!errorDiv) return;
  errorDiv.textContent = message;
  errorDiv.classList.remove('d-none');
}

function _generateUUID() {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) {
    return crypto.randomUUID();
  }
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}
function _handleSaveItem() {
  const editIndexRaw = document.getElementById('field-editIndex')
    ? document.getElementById('field-editIndex').value : '';
  const isEdit = editIndexRaw !== '' && editIndexRaw !== null;

  if (!isEdit && state.items.length >= MAX_ITEMS) {
    _showModalError('Maximum item limit (' + MAX_ITEMS + ') reached. Please delete an item before adding a new one.');
    return;
  }

  const type = (document.getElementById('field-type') || {}).value || '';
  const category = (document.getElementById('field-category') || {}).value || '';
  const name = ((document.getElementById('field-name') || {}).value || '').trim();
  const amountRaw = (document.getElementById('field-amount') || {}).value;
  const rateRaw = (document.getElementById('field-rate') || {}).value;
  const startYearRaw = (document.getElementById('field-startYear') || {}).value;
  const endYearRaw = (document.getElementById('field-endYear') || {}).value;
  const noEndDateChecked = document.getElementById('noEndDate')
    ? document.getElementById('noEndDate').checked : false;

  if (!type) { _showModalError('Type is required.'); return; }
  if (!category) { _showModalError('Category is required.'); return; }
  if (!name) { _showModalError('Name is required.'); return; }
  if (amountRaw === '' || amountRaw === null || amountRaw === undefined) { _showModalError('Amount is required.'); return; }
  if (startYearRaw === '' || startYearRaw === null) { _showModalError('Start Year is required.'); return; }
  if (!noEndDateChecked) {
    if (endYearRaw === '' || endYearRaw === null) { _showModalError('End Year is required.'); return; }
  }

  const amount = Number(amountRaw);
  const rate = rateRaw !== '' ? Number(rateRaw) : 0;
  const startYear = Number(startYearRaw);
  const endYear = noEndDateChecked ? null : Number(endYearRaw);

  if (!isFinite(amount)) { _showModalError('Amount must be a valid number.'); return; }
  if (!isFinite(rate)) { _showModalError('Rate must be a valid number.'); return; }
  if (!isFinite(startYear)) { _showModalError('Start Year must be a valid number.'); return; }
  if (endYear !== null) {
    if (!isFinite(endYear)) { _showModalError('End Year must be a valid number.'); return; }
    if (startYear > endYear) { _showModalError('Start Year must be less than or equal to End Year.'); return; }
  }

  let contributionAmount = null, contributionFrequency = null, contributionEndYear = null;
  if (type === 'bank' || type === 'investments') {
    const v = (document.getElementById('field-contributionAmount') || {}).value;
    if (v !== '' && v != null) {
      const val = Number(v);
      if (!isFinite(val) || val < 0) { _showModalError('Contribution Amount must be a finite non-negative number.'); return; }
      contributionAmount = val;
      contributionFrequency = (document.getElementById('field-contributionFrequency') || {}).value || 'monthly';
    }
    const ceyRaw = (document.getElementById('field-contributionEndYear') || {}).value;
    if (ceyRaw !== '' && ceyRaw != null) {
      const ceyVal = Number(ceyRaw);
      if (!isFinite(ceyVal)) { _showModalError('Contribution End Year must be a valid number.'); return; }
      if (ceyVal < startYear) { _showModalError('Contribution End Year must be \u2265 Start Year.'); return; }
      contributionEndYear = ceyVal;
    }
  }

  let withdrawalAmount = null, withdrawalFrequency = null;
  if (ASSET_TYPES.includes(type)) {
    const v = (document.getElementById('field-withdrawalAmount') || {}).value;
    if (v !== '' && v != null) {
      const val = Number(v);
      if (!isFinite(val) || val < 0) { _showModalError('Withdrawal Amount must be a finite non-negative number.'); return; }
      withdrawalAmount = val;
      withdrawalFrequency = (document.getElementById('field-withdrawalFrequency') || {}).value || 'monthly';
    }
  }

  let loan = null;
  if (type === 'property' || type === 'vehicles') {
    const la = (document.getElementById('field-loanAmount') || {}).value;
    if (la !== '' && la != null) {
      const lav = Number(la); if (!isFinite(lav) || lav < 0) { _showModalError('Loan Amount must be a finite non-negative number.'); return; }
      const lr = (document.getElementById('field-loanRate') || {}).value;
      const lrv = lr !== '' ? Number(lr) : 0; if (!isFinite(lrv) || lrv < 0) { _showModalError('Loan Interest Rate must be a finite non-negative number.'); return; }
      const lp = (document.getElementById('field-loanPayment') || {}).value;
      if (lp === '' || lp == null) { _showModalError('Monthly Payment is required when Loan Amount is provided.'); return; }
      const lpv = Number(lp); if (!isFinite(lpv) || lpv < 0) { _showModalError('Monthly Payment must be a finite non-negative number.'); return; }
      const le = (document.getElementById('field-loanEscrow') || {}).value;
      const lev = le !== '' ? Number(le) : 0; if (!isFinite(lev) || lev < 0) { _showModalError('Escrow Monthly must be a finite non-negative number.'); return; }
      const lt = (document.getElementById('field-loanPropertyTax') || {}).value;
      const ltv = lt !== '' ? Number(lt) : 0; if (!isFinite(ltv) || ltv < 0) { _showModalError('Property Tax Annual must be a finite non-negative number.'); return; }
      const lx = (document.getElementById('field-loanExtra') || {}).value;
      const lxv = lx !== '' ? Number(lx) : 0; if (!isFinite(lxv) || lxv < 0) { _showModalError('Extra Monthly Payment must be a finite non-negative number.'); return; }
      loan = { loanAmount: lav, annualInterestRate: lrv, monthlyPayment: lpv, escrowMonthly: lev, propertyTaxAnnual: ltv, extraMonthlyPayment: lxv };
    }
  }

  let retirement401k = null;
  if (category === 'Traditional 401(k)' || category === 'Roth 401(k)') {
    const ec = (document.getElementById('field-employeeContribution') || {}).value;
    if (ec !== '' && ec != null) {
      const ecv = Number(ec); if (!isFinite(ecv) || ecv < 0) { _showModalError('Employee Contribution must be a finite non-negative number.'); return; }
      const em = (document.getElementById('field-employerMatchPct') || {}).value;
      const emv = em !== '' ? Number(em) : 0; if (!isFinite(emv) || emv < 0) { _showModalError('Employer Match % must be a finite non-negative number.'); return; }
      const mc = (document.getElementById('field-matchCapPct') || {}).value;
      const mcv = mc !== '' ? Number(mc) : 0; if (!isFinite(mcv) || mcv < 0) { _showModalError('Match Cap % must be a finite non-negative number.'); return; }
      const as = (document.getElementById('field-annualSalary') || {}).value;
      const asv = as !== '' ? Number(as) : 0; if (!isFinite(asv) || asv < 0) { _showModalError('Annual Salary must be a finite non-negative number.'); return; }
      const vy = (document.getElementById('field-vestingYears') || {}).value;
      const vyv = vy !== '' ? Number(vy) : 0;
      if (!isFinite(vyv) || vyv < 0 || !Number.isInteger(vyv)) { _showModalError('Vesting Years must be an integer \u2265 0.'); return; }
      const ws = (document.getElementById('field-withdrawalStartYear') || {}).value;
      const wsv = (ws !== '' && ws != null) ? Number(ws) : null;
      if (wsv !== null && !isFinite(wsv)) { _showModalError('Withdrawal Start Year must be a valid number.'); return; }
      retirement401k = { employeeContribution: ecv, employerMatchPct: emv, employerMatchCapPct: mcv, annualSalary: asv, vestingYears: vyv, withdrawalStartYear: wsv };
    }
  }

  if (isEdit) {
    const editIndex = Number(editIndexRaw);
    state.items[editIndex] = Object.assign({}, state.items[editIndex], {
      type, category, name, amount, rate, startYear, endYear,
      contributionAmount, contributionFrequency, contributionEndYear, withdrawalAmount, withdrawalFrequency, loan, retirement401k
    });
  } else {
    state.items.push({
      id: _generateUUID(), type, category, name, amount, rate, startYear, endYear,
      createdAt: new Date().toISOString(),
      contributionAmount, contributionFrequency, contributionEndYear, withdrawalAmount, withdrawalFrequency, loan, retirement401k
    });
  }

  saveItems(state.items);
  render();
  closeModal();
}

// Wire save button when DOM is ready
if (typeof document !== 'undefined') {
  document.addEventListener('DOMContentLoaded', () => {
    const saveBtn = document.getElementById('btn-save-item');
    if (saveBtn) saveBtn.addEventListener('click', _handleSaveItem);
  });
}
function initiateDelete(index) {
  const row = document.querySelector('[data-item-index="' + index + '"]');
  if (!row) return;
  const actionArea = row.querySelector('.item-action-area');
  if (!actionArea) return;
  actionArea.innerHTML =
    '<span class="text-danger me-1 small">Delete?</span>' +
    '<button class="btn btn-danger btn-sm me-1" onclick="confirmDelete(' + index + ')">Yes</button>' +
    '<button class="btn btn-secondary btn-sm" onclick="cancelDelete(' + index + ')">No</button>';
}
function confirmDelete(index) {
  state.items.splice(index, 1);
  saveItems(state.items);
  render();
}
function cancelDelete(index) {
  render();
}


// --- js/eventHandlers.js ---
// =============================================================================
// EventHandlers — sidebar navigation, settings panel, DOMContentLoaded init
// =============================================================================
function applyTheme(theme) {
  const t = theme || DEFAULT_SETTINGS.theme;
  document.documentElement.style.setProperty('--bg', t.background || DEFAULT_SETTINGS.theme.background);
  document.documentElement.style.setProperty('--surface', t.surface || DEFAULT_SETTINGS.theme.surface);
  document.documentElement.style.setProperty('--text', t.text || DEFAULT_SETTINGS.theme.text);
  document.documentElement.style.setProperty('--accent', t.accent || DEFAULT_SETTINGS.theme.accent);
  if (t.fontFamily) document.body.style.fontFamily = t.fontFamily;
  if (t.fontSize) document.body.style.fontSize = t.fontSize + 'px';
}

function _showStorageToast(message) {
  let toastContainer = document.getElementById('rcfp-toast-container');
  if (!toastContainer) {
    toastContainer = document.createElement('div');
    toastContainer.id = 'rcfp-toast-container';
    toastContainer.className = 'toast-container position-fixed bottom-0 end-0 p-3';
    toastContainer.style.zIndex = '9999';
    document.body.appendChild(toastContainer);
  }
  const toastEl = document.createElement('div');
  toastEl.className = 'toast align-items-center text-bg-danger border-0';
  toastEl.setAttribute('role', 'alert');
  toastEl.setAttribute('aria-live', 'assertive');
  toastEl.setAttribute('aria-atomic', 'true');
  toastEl.innerHTML =
    '<div class="d-flex">' +
      '<div class="toast-body">' + _escapeHtml(message) + '</div>' +
      '<button type="button" class="btn-close btn-close-white me-2 m-auto" data-bs-dismiss="toast" aria-label="Close"></button>' +
    '</div>';
  toastContainer.appendChild(toastEl);
  if (typeof bootstrap !== 'undefined') {
    const toast = new bootstrap.Toast(toastEl, { delay: 5000 });
    toast.show();
    toastEl.addEventListener('hidden.bs.toast', () => toastEl.remove());
  }
}

function _showInfoAlert(message) {
  const mainContent = document.getElementById('main-content');
  if (!mainContent) return;
  const alert = document.createElement('div');
  alert.className = 'alert alert-info alert-dismissible fade show';
  alert.setAttribute('role', 'alert');
  alert.innerHTML =
    _escapeHtml(message) +
    '<button type="button" class="btn-close" data-bs-dismiss="alert" aria-label="Close"></button>';
  const header = document.getElementById('main-header');
  if (header && header.nextSibling) {
    mainContent.insertBefore(alert, header.nextSibling);
  } else {
    mainContent.prepend(alert);
  }
  setTimeout(() => {
    if (typeof bootstrap !== 'undefined') {
      const bsAlert = bootstrap.Alert.getOrCreateInstance(alert);
      bsAlert.close();
    } else {
      alert.remove();
    }
  }, 5000);
}

if (typeof document !== 'undefined') {
  document.addEventListener('DOMContentLoaded', () => {
    // Sidebar navigation
    const navLinks = document.querySelectorAll('#sidebar .nav-link[data-section]');
    navLinks.forEach(link => {
      link.addEventListener('click', (e) => {
        e.preventDefault();
        state.activeSection = link.dataset.section;
        render();
      });
    });

    // Add item button
    const addBtn = document.getElementById('btn-add-item');
    if (addBtn) {
      addBtn.addEventListener('click', () => { openAddModal(state.activeSection); });
    }

    // Wire type select change
    const typeSelect = document.getElementById('field-type');
    if (typeSelect) {
      typeSelect.addEventListener('change', () => {
        const selectedType = typeSelect.value;
        _populateCategorySelect(selectedType);
        const cs = document.getElementById('field-category');
        _updateFieldGroupVisibility(selectedType, cs ? cs.value : '');
      });
    }

    // Wire category select change
    const categorySelect = document.getElementById('field-category');
    if (categorySelect) {
      categorySelect.addEventListener('change', () => {
        const currentType = (document.getElementById('field-type') || {}).value || '';
        _updateFieldGroupVisibility(currentType, categorySelect.value);
      });
    }

    // Wire "No end date" checkbox
    const noEndDateCheckbox = document.getElementById('noEndDate');
    if (noEndDateCheckbox) {
      noEndDateCheckbox.addEventListener('change', () => {
        const endYearField = document.getElementById('field-endYear');
        if (noEndDateCheckbox.checked) {
          if (endYearField) { endYearField.value = ''; endYearField.disabled = true; endYearField.required = false; }
        } else {
          if (endYearField) { endYearField.disabled = false; endYearField.required = true; }
        }
      });
    }

    // Populate settings inputs
    const chartTitleInput = document.getElementById('setting-chartTitle');
    if (chartTitleInput) chartTitleInput.value = state.settings.chartTitle || '';
    const startYearInput = document.getElementById('setting-startYear');
    if (startYearInput) startYearInput.value = state.settings.startYear || DEFAULT_SETTINGS.startYear;
    const projectionYearsInput = document.getElementById('setting-projectionYears');
    if (projectionYearsInput) projectionYearsInput.value = state.settings.projectionYears || DEFAULT_SETTINGS.projectionYears;
    const bgInput = document.getElementById('setting-bg');
    if (bgInput) bgInput.value = (state.settings.theme && state.settings.theme.background) || DEFAULT_SETTINGS.theme.background;
    const surfaceInput = document.getElementById('setting-surface');
    if (surfaceInput) surfaceInput.value = (state.settings.theme && state.settings.theme.surface) || DEFAULT_SETTINGS.theme.surface;
    const textInput = document.getElementById('setting-text');
    if (textInput) textInput.value = (state.settings.theme && state.settings.theme.text) || DEFAULT_SETTINGS.theme.text;
    const accentInput = document.getElementById('setting-accent');
    if (accentInput) accentInput.value = (state.settings.theme && state.settings.theme.accent) || DEFAULT_SETTINGS.theme.accent;
    const fontFamilyInput = document.getElementById('setting-fontFamily');
    if (fontFamilyInput) fontFamilyInput.value = (state.settings.theme && state.settings.theme.fontFamily) || DEFAULT_SETTINGS.theme.fontFamily;
    const fontSizeInput = document.getElementById('setting-fontSize');
    if (fontSizeInput) fontSizeInput.value = (state.settings.theme && state.settings.theme.fontSize) || DEFAULT_SETTINGS.theme.fontSize;

    // Wire settings change handlers
    if (chartTitleInput) {
      chartTitleInput.addEventListener('input', () => {
        state.settings.chartTitle = chartTitleInput.value;
        try { saveSettings(state.settings); } catch (err) { _showStorageToast('Storage quota exceeded.'); }
        render();
      });
    }
    if (startYearInput) {
      startYearInput.addEventListener('change', () => {
        state.settings.startYear = Number(startYearInput.value);
        try { saveSettings(state.settings); } catch (err) { _showStorageToast('Storage quota exceeded.'); }
        render();
      });
    }
    if (projectionYearsInput) {
      projectionYearsInput.addEventListener('change', () => {
        state.settings.projectionYears = Number(projectionYearsInput.value);
        try { saveSettings(state.settings); } catch (err) { _showStorageToast('Storage quota exceeded.'); }
        render();
      });
    }

    // Wire color pickers
    const colorMap = { 'setting-bg': 'background', 'setting-surface': 'surface', 'setting-text': 'text', 'setting-accent': 'accent' };
    const cssPropMap = { background: '--bg', surface: '--surface', text: '--text', accent: '--accent' };
    Object.entries(colorMap).forEach(([inputId, themeKey]) => {
      const input = document.getElementById(inputId);
      if (!input) return;
      input.addEventListener('input', () => {
        if (!state.settings.theme) state.settings.theme = Object.assign({}, DEFAULT_SETTINGS.theme);
        state.settings.theme[themeKey] = input.value;
        document.documentElement.style.setProperty(cssPropMap[themeKey], input.value);
        try { saveSettings(state.settings); } catch (err) { _showStorageToast('Storage quota exceeded.'); }
        render();
      });
    });

    if (fontFamilyInput) {
      fontFamilyInput.addEventListener('input', () => {
        if (!state.settings.theme) state.settings.theme = Object.assign({}, DEFAULT_SETTINGS.theme);
        state.settings.theme.fontFamily = fontFamilyInput.value;
        document.body.style.fontFamily = fontFamilyInput.value;
        try { saveSettings(state.settings); } catch (err) { _showStorageToast('Storage quota exceeded.'); }
      });
    }
    if (fontSizeInput) {
      fontSizeInput.addEventListener('change', () => {
        if (!state.settings.theme) state.settings.theme = Object.assign({}, DEFAULT_SETTINGS.theme);
        state.settings.theme.fontSize = Number(fontSizeInput.value);
        document.body.style.fontSize = fontSizeInput.value + 'px';
        try { saveSettings(state.settings); } catch (err) { _showStorageToast('Storage quota exceeded.'); }
      });
    }

    // Populate and wire tax settings inputs
    const taxFilingStatus = document.getElementById('taxFilingStatus');
    const taxBirthYear = document.getElementById('taxBirthYear');
    const taxSSBenefit = document.getElementById('taxSSBenefit');
    const taxSSStartYear = document.getElementById('taxSSStartYear');
    const taxInflationRate = document.getElementById('taxInflationRate');

    const tax = state.settings.tax || DEFAULT_SETTINGS.tax;
    if (taxFilingStatus) taxFilingStatus.value = tax.filingStatus || 'single';
    if (taxBirthYear) taxBirthYear.value = tax.birthYear || DEFAULT_SETTINGS.tax.birthYear;
    if (taxSSBenefit) taxSSBenefit.value = tax.annualSocialSecurityBenefit || 0;
    if (taxSSStartYear) taxSSStartYear.value = tax.socialSecurityStartYear != null ? tax.socialSecurityStartYear : '';
    if (taxInflationRate) taxInflationRate.value = tax.bracketInflationRate != null ? tax.bracketInflationRate : DEFAULT_SETTINGS.tax.bracketInflationRate;

    const wireTaxInput = (el, key, isNumber) => {
      if (!el) return;
      el.addEventListener('change', () => {
        if (!state.settings.tax) state.settings.tax = Object.assign({}, DEFAULT_SETTINGS.tax);
        state.settings.tax[key] = isNumber ? (el.value !== '' ? Number(el.value) : null) : el.value;
        try { saveSettings(state.settings); } catch (err) { _showStorageToast('Storage quota exceeded.'); }
        render();
      });
    };
    wireTaxInput(taxFilingStatus, 'filingStatus', false);
    wireTaxInput(taxBirthYear, 'birthYear', true);
    wireTaxInput(taxSSBenefit, 'annualSocialSecurityBenefit', true);
    wireTaxInput(taxSSStartYear, 'socialSecurityStartYear', true);
    wireTaxInput(taxInflationRate, 'bracketInflationRate', true);

    // Apply loaded theme and initialize UI
    applyTheme(state.settings.theme);
    render();

    // Export Excel
    const exportBtn = document.getElementById('btn-export');
    if (exportBtn) {
      exportBtn.addEventListener('click', () => { exportToXlsx(state.items); });
    }

    // Import Excel
    const importFile = document.getElementById('import-file');
    if (importFile) {
      importFile.addEventListener('change', () => {
        const file = importFile.files[0];
        if (!file) return;
        importFromXlsx(file)
          .then(result => {
            state.items = result.items;
            saveItems(state.items);
            render();
            importFile.value = '';
            if (result.skipped > 0) {
              _showInfoAlert('Import complete. ' + result.skipped + ' row(s) were skipped due to missing required fields.');
            }
          })
          .catch(err => {
            importFile.value = '';
            _showStorageToast(err.message || 'Only .xlsx files are supported. No data was changed.');
          });
      });
    }
  });
}


